        const redirectPath = `${freshPath}${separator}session=${encodeURIComponent(sessionId)}&pluginLogin=true`;
        const signInPath = `/studio/sign-in?redirect_url=${encodeURIComponent(redirectPath)}`;
        const signInUrl = `${serviceUrl}${signInPath}&session=${encodeURIComponent(sessionId)}`;
