/**
 * Starts the single event polling loop for a Studio session. Returns an
 * abort function.
 *
 * The pointer is removed ONLY on proof the window is gone: a
 * `studio:window-closed` event (the browser's `beforeunload` beacon — the one
 * signal nothing emits optimistically). It clears after a grace window so a
 * page refresh (window-closed, then `session-started` from the reload) cancels
 * the cleanup. The only other clears in the whole system are `closeStudio`
 * (which also waits for a confirmed window-closed) and the explicit
 * `clearStudioSession` recovery after a not-responding gate.
 *
 * `studio:session-ended` is the logical "end session" signal: it terminates
 * the command (forwarded once; commands key on it) but NEVER clears the
 * pointer — the web emits it before attempting `window.close()`, which the
 * browser can refuse, so the window may still be alive (parked on the close
 * page) and reusable by the next open. `studio:session-closed` (the close
 * flow completed) is informational and ignored here for the same reason.
 *
 * A window-closed with no preceding session-ended (manual tab close) still
 * terminates the command: after the grace expires it clears and forwards a
 * synthetic `session-ended` so the command's existing terminal logic runs.
 */
function startEventPoller(serviceUrl, apiKey, sessionId, onEvent, restoreFocus) {
    const abortController = new AbortController();
    let endedNotified = false;
    // Forward the terminal `session-ended` to the command exactly once (it may
    // arrive both for real and synthesized from a window-closed) and stop the
    // loop. `baseEvent` seeds the synthetic event in the window-closed case.
    const notifyEnded = (baseEvent) => {
        if (!endedNotified) {
            endedNotified = true;
            restoreFocus();
            onEvent({ ...baseEvent, type: "studio:session-ended" });
        }
        abortController.abort();
    };
    // The shared arbiter owns the window-closed vs page-refresh disambiguation.
    // A confirmed teardown is the only thing that clears the pointer here.
    const arbiter = createWindowCloseArbiter({
        onConfirmed: (event) => {
            clearActiveStudioSession(sessionId);
            notifyEnded(event);
        },
        onRefuted: () => {
            console.error("Studio reconnected after page refresh");
        },
    });
    const done = (async () => {
        // Attach strictly AFTER the current stream tip: replayed history must not
        // drive the lifecycle. Reuse keeps ended-but-alive sessions around by
        // design, so the stream can legitimately contain an old `session-ended`
        // (or a previous run's terminal command events) that would instantly
        // terminate this command if replayed.
        const startCursor = await fetchStreamTip({ serviceUrl, apiKey, sessionId });
        if (abortController.signal.aborted) {
            return;
        }
        await pollAgentSessionEvents({
            serviceUrl,
            apiKey,
            sessionId,
            startCursor,
            abortSignal: abortController.signal,
            onEvent: (event) => {
                if (event.type === "studio:window-closed" ||
                    event.type === "studio:session-started") {
                    // Real teardown (`beforeunload`) vs page refresh: the arbiter holds
                    // the candidate through the grace window and clears the pointer only
                    // on a confirmed teardown (its onConfirmed above).
                    arbiter.handleEvent(event);
                    return;
                }
                if (event.type === "studio:session-ended") {
                    // Logical end only — NOT proof the window closed. Terminate the
                    // command but keep the pointer: if no window-closed ever arrives the
                    // window is still alive and the next open reuses it. The deliberate
                    // agent-driven close path (`closeStudio`) owns the confirmed-close
                    // clear.
                    //
                    // Only live page JS emits session-ended, so the window is alive right
                    // now — any PENDING grace candidate (armed by an earlier
                    // window-closed, i.e. a refresh teardown) is stale evidence and must
                    // not clear a live window's pointer. Cancel it like session-started
                    // does. The confirmed-deliberate-close order (session-ended THEN
                    // window-closed) is unaffected: its candidate is armed after this
                    // handler ran.
                    arbiter.cancel();
                    notifyEnded(event);
                    return;
                }
                if (event.type === "studio:session-closed") {
                    // Close flow completed — informational, never clears (the close
                    // attempt it reports can still be refused by the browser).
                    return;
                }
                if (event.type === "studio:not-member") {
                    restoreFocus();
                    onEvent(event);
                    abortController.abort();
                    return;
                }
                if (event.type === "studio:return-to-agent" ||
                    event.type === "studio:edit-with-agent") {
                    restoreFocus();
                }
                onEvent(event);
            },
            onError: (err) => {
                console.error(`studio agent-event poll: ${err.message}`);
            },
        });
    })().catch((err) => {
        if (!abortController.signal.aborted) {
            console.error(`studio agent-event poll terminated: ${err.message}`);
        }
    });
    return { abort: () => abortController.abort(), done };
}
/**
 * CLI runner. Parses args and calls openStudioTo.
 */
export async function runOpenStudioTo(platform) {
    let path = process.argv.slice(2).find((a) => !a.startsWith("--"));
    if (!path) {
        console.error("Usage: openStudioTo <path>");
        process.exit(1);
    }
    if (!path.startsWith("/studio")) {
        path = "/studio";
    }
    if (!isValidStudioRoute(path)) {
        console.error(`Studio route not allowed: ${path}`);
        process.exit(1);
    }
    try {
        const result = await openStudioTo(path, {
            clientHeaders: {
                "x-bitfab-client-name": platform.cliBinary,
                "x-bitfab-client-display-name": platform.displayName,
            },
            onLoginRequired: (sessionId, signInUrl) => {
                emitJson({ event: "auth-required", sessionId, signInUrl });
            },
            onAuthenticated: (sessionId) => {
                emitJson({ event: "authenticated", sessionId });
            },
            onEvent: (event) => {
                const data = event.data;
                const payload = {
                    event: event.type.replace("studio:", ""),
                    sessionId: result.sessionId,
                };
                if (data.datasetId) {
                    payload.datasetId = data.datasetId;
                }
                if (data.path) {
                    payload.path = data.path;
                }
                if (data.search) {
                    payload.search = data.search;
                }
                if (data.token) {
                    payload.token = data.token;
                }
                emitJson(payload);
            },
        });
        if (result.opened) {
            emitJson({ event: "started", sessionId: result.sessionId });
        }
        else {
            emitJson({ event: "navigated", sessionId: result.sessionId, path });
        }
        const shutdown = () => {
            result.abort();
            process.exit(0);
        };
        process.on("SIGINT", shutdown);
        process.on("SIGTERM", shutdown);
        await result.done;
    }
    catch (err) {
        if (err instanceof StudioNavigationError &&
            err.staleSessionId &&
            isUnreachable(err.reason)) {
            emitJson({
                event: "not-responding",
                sessionId: err.staleSessionId,
                path,
            });
        }
        else if (err instanceof StudioNavigationError) {
            // Blocked / invalid-route: a live tab refused, or a bad path. Surface it
            // rather than prompting a clear-and-reopen that would duplicate a healthy
            // window.
            emitJson({
                event: "open-failed",
                sessionId: "none",
                reason: err.blockedReason ?? err.message,
            });
        }
        else {
            emitJson({
                event: "open-failed",
                sessionId: "none",
                reason: err.message,
            });
        }
        process.exit(1);
    }
}
